import 'package:flutter/material.dart'; class CustomTextField extends StatelessWidget { final String label; final String? hint; final TextEditingController? controller; final bool obscure; final TextInputType? keyboardType; const CustomTextField({super.key, required this.label, this.hint, this.controller, this.obscure=false, this.keyboardType}); @override Widget build(BuildContext context) => Column(crossAxisAlignment:CrossAxisAlignment.start, children:[Text(label,style:const TextStyle(fontSize:13,fontWeight:FontWeight.w600)),const SizedBox(height:6),TextField(controller:controller,obscureText:obscure,keyboardType:keyboardType,decoration:InputDecoration(hintText:hint,border:const OutlineInputBorder()))]); }
